const data = $input.first().json;

function makeSlug(nome) {
  const semTam = nome.replace(/\s+(\d+(\/\d+)?(\s+un)?|un)\)\s*$/, ')').replace(/[()]/g, ' ');
  return semTam
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '');
}

if (data.data && Array.isArray(data.data)) {
  const comEstoque = data.data
    .filter(item => item.quantidadeDisponivelVenda > 0)
    .map(item => {
      const derivNome = item.descricaoProduto.split(' - ').pop() || item.descricaoProduto;
      const slug = makeSlug(derivNome);
      return {
        descricao: item.descricaoProduto,
        quantidade: item.quantidadeDisponivelVenda,
        sku: item.produto,
        link: 'https://www.chinelarialeilaneneves.com.br/' + slug
      };
    });
  const semEstoque = data.data.filter(item => item.quantidadeDisponivelVenda === 0).length;
  return [{ json: { com_estoque: comEstoque.length, sem_estoque: semEstoque, itens: comEstoque } }];
}

return [{ json: { erro: 'Nao foi possivel consultar estoque' } }];
